import React, { useState, useEffect } from 'react';
import { dashboardAPI } from '../services/api';
import { toast } from 'react-toastify';
import { PieChart, Pie, Cell, AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
const COLORS = ['#6366f1','#8b5cf6','#a855f7','#ec4899','#f43f5e','#f59e0b','#22c55e','#06b6d4'];
const DashboardPage = () => {
  const [summary, setSummary] = useState(null);
  const [cats, setCats] = useState(null);
  const [trend, setTrend] = useState(null);
  const [period, setPeriod] = useState('month');
  const [loading, setLoading] = useState(true);
  useEffect(() => { load(); }, [period]);
  const load = async () => { setLoading(true); try { const [s,c,t] = await Promise.all([dashboardAPI.getSummary(period),dashboardAPI.getCategoryBreakdown(period,'expense'),dashboardAPI.getMonthlyTrend(6)]); setSummary(s.data); setCats(c.data); setTrend(t.data); } catch { toast.error('Failed'); } finally { setLoading(false); } };
  if (loading) return <div style={{display:'flex',justifyContent:'center',alignItems:'center',height:'80vh',fontSize:24}}>Loading...</div>;
  const cards = [{l:'Income',v:'$'+(summary?.total_income?.toLocaleString()||'0'),c:'#22c55e'},{l:'Expenses',v:'$'+(summary?.total_expense?.toLocaleString()||'0'),c:'#ef4444'},{l:'Balance',v:'$'+(summary?.balance?.toLocaleString()||'0'),c:summary?.balance>=0?'#22c55e':'#ef4444'},{l:'Budget',v:(summary?.budget_percentage?.toFixed(1)||0)+'%',c:'#f59e0b'}];
  return <div style={{padding:24,maxWidth:1200,margin:'0 auto'}}>
    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:32,flexWrap:'wrap',gap:8}}>
      <h1 style={{fontSize:28,fontWeight:'bold'}}>Dashboard</h1>
      <div style={{display:'flex',gap:8}}>{['week','month','year','all'].map(p=><button key={p} onClick={()=>setPeriod(p)} className={period===p?'gradient-bg':''} style={{padding:'8px 16px',borderRadius:8,border:'none',color:'#fff',cursor:'pointer',textTransform:'capitalize',background:period===p?undefined:'rgba(255,255,255,0.05)'}}>{p}</button>)}</div>
    </div>
    <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(220px,1fr))',gap:24,marginBottom:32}}>
      {cards.map((c,i)=><div key={i} className='glass card-hover' style={{padding:24}}><p style={{color:'#9ca3af',fontSize:14}}>{c.l}</p><p style={{fontSize:28,fontWeight:'bold',color:c.c,marginTop:8}}>{c.v}</p></div>)}
    </div>
    <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(400px,1fr))',gap:24}}>
      <div className='glass' style={{padding:24}}><h2 style={{marginBottom:16}}>Categories</h2>
        {cats?.categories?.length>0?<ResponsiveContainer width='100%' height={300}><PieChart><Pie data={cats.categories} cx='50%' cy='50%' outerRadius={100} dataKey='total' nameKey='category' label={({category,percentage})=>category+' '+percentage+'%'}>{cats.categories.map((e,i)=><Cell key={i} fill={COLORS[i%COLORS.length]}/>)}</Pie><Tooltip contentStyle={{backgroundColor:'#1e1b4b',border:'1px solid rgba(255,255,255,0.1)',borderRadius:8}}/></PieChart></ResponsiveContainer>:<p style={{color:'#6b7280',textAlign:'center',padding:48}}>No data</p>}
      </div>
      <div className='glass' style={{padding:24}}><h2 style={{marginBottom:16}}>Trend</h2>
        {trend?.trend?.length>0?<ResponsiveContainer width='100%' height={300}><AreaChart data={trend.trend}><CartesianGrid strokeDasharray='3 3' stroke='rgba(255,255,255,0.1)'/><XAxis dataKey='month' stroke='#9ca3af'/><YAxis stroke='#9ca3af'/><Tooltip contentStyle={{backgroundColor:'#1e1b4b',border:'1px solid rgba(255,255,255,0.1)',borderRadius:8}}/><Area type='monotone' dataKey='income' stroke='#22c55e' fill='rgba(34,197,94,0.2)'/><Area type='monotone' dataKey='expense' stroke='#ef4444' fill='rgba(239,68,68,0.2)'/></AreaChart></ResponsiveContainer>:<p style={{color:'#6b7280',textAlign:'center',padding:48}}>No data</p>}
      </div>
    </div></div>;
};
export default DashboardPage;
